import{_ as o,c as t,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"添加账号: OAuth 与 Refresh Token 双通道 | Antigravity Tools","description":"学习 Antigravity Tools 添加账号的两种方式。通过 OAuth 一键授权或 Refresh Token 手动添加，支持批量导入，处理回调失败并验证账号池。","frontmatter":{"title":"添加账号: OAuth 与 Refresh Token 双通道 | Antigravity Tools","sidebarTitle":"加你的 Google 号","subtitle":"添加账号：OAuth/Refresh Token 双通道与最佳实践","description":"学习 Antigravity Tools 添加账号的两种方式。通过 OAuth 一键授权或 Refresh Token 手动添加，支持批量导入，处理回调失败并验证账号池。","tags":["账号管理","OAuth","refresh_token","Google","最佳实践"],"prerequisite":["start-getting-started"],"duration":15,"order":4},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/start/add-account/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/start/add-account/index.md"}'),c={name:"zh/lbjlaq/Antigravity-Manager/start/add-account/index.md"};function d(l,e,s,n,i,h){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="添加账号-oauth-refresh-token-双通道与最佳实践" tabindex="-1">添加账号：OAuth/Refresh Token 双通道与最佳实践 <a class="header-anchor" href="#添加账号-oauth-refresh-token-双通道与最佳实践" aria-label="Permalink to &quot;添加账号：OAuth/Refresh Token 双通道与最佳实践&quot;">​</a></h1><p>在 Antigravity Tools 里，“添加账号”就是把 Google 账号的 <code>refresh_token</code> 写进本地账号池，让后续反代请求可以轮换使用。你可以走 OAuth 一键授权，也可以直接粘贴 <code>refresh_token</code> 手动添加。</p><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>用 OAuth 或 Refresh Token，把 Google 账号加进 Antigravity Tools 的账号池</li><li>复制/手动打开授权链接，并在回调成功后自动完成添加</li><li>遇到拿不到 <code>refresh_token</code>、回调连不上 <code>localhost</code> 这类问题时，知道应该怎么处理</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><ul><li>点了“OAuth 授权”却一直转圈，或者浏览器提示 <code>localhost refused to connect</code></li><li>授权成功了，但提示“未获取到 Refresh Token”</li><li>你手里只有 <code>refresh_token</code>，不知道怎么一次性批量导入</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><ul><li>你想用最稳的方式把账号加进来（优先 OAuth）</li><li>你更在意可迁移/可备份（Refresh Token 更适合做“账号池资产”）</li><li>你要加很多号，想批量导入 <code>refresh_token</code>（支持从文本/JSON 里提取）</li></ul><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><ul><li>你已经安装并能打开 Antigravity Tools 桌面端</li><li>你知道入口在哪：左侧导航进入 <code>Accounts</code> 页面（路由见 <code>source/lbjlaq/Antigravity-Manager/src/App.tsx</code>）</li></ul><div class="info custom-block"><p class="custom-block-title">这节课里的两个关键词</p><p><strong>OAuth</strong>：一种&quot;跳到浏览器登录并授权&quot;的流程。Antigravity Tools 会在本地临时起一个回调地址（<code>http://localhost/127.0.0.1/[::1]:&lt;port&gt;/oauth-callback</code>，根据系统 IPv4/IPv6 监听情况自动选择），等浏览器带着 <code>code</code> 回来后再换取 token。（实现见 <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs</code>）</p><p><strong>refresh_token</strong>：一种&quot;可以长期用来刷新 access_token 的凭据&quot;。本项目添加账号时会用它先换取 access_token，再去 Google 拉取真实邮箱，并忽略你在前端输入的 email。（实现见 <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs</code>）</p></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Antigravity Tools 的“添加账号”，最终都是为了拿到一份可用的 <code>refresh_token</code>，并把账号信息写入本地账号池。</p><ul><li><strong>OAuth 通道</strong>：应用帮你生成授权链接并监听本地回调；授权完成后自动换取 token 并保存账号（见 <code>prepare_oauth_url</code>、<code>start_oauth_login</code>、<code>complete_oauth_login</code>）</li><li><strong>Refresh Token 通道</strong>：你直接把 <code>refresh_token</code> 粘贴进来，应用会用它刷新 access_token，并向 Google 获取真实邮箱来落盘（见 <code>add_account</code>）</li></ul><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-打开-添加账号-弹窗" tabindex="-1">第 1 步：打开“添加账号”弹窗 <a class="header-anchor" href="#第-1-步-打开-添加账号-弹窗" aria-label="Permalink to &quot;第 1 步：打开“添加账号”弹窗&quot;">​</a></h3><p><strong>为什么</strong> 所有添加入口都在 <code>Accounts</code> 页面统一收口。</p><p>操作：进入 <code>Accounts</code> 页面，点右侧的 <strong>Add Account</strong> 按钮（组件：<code>AddAccountDialog</code>）。</p><p><strong>你应该看到</strong>：弹出一个包含 3 个标签页的弹窗：<code>OAuth</code> / <code>Refresh Token</code> / <code>Import</code>（见 <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx</code>）。</p><h3 id="第-2-步-优先用-oauth-一键授权-推荐" tabindex="-1">第 2 步：优先用 OAuth 一键授权（推荐） <a class="header-anchor" href="#第-2-步-优先用-oauth-一键授权-推荐" aria-label="Permalink to &quot;第 2 步：优先用 OAuth 一键授权（推荐）&quot;">​</a></h3><p><strong>为什么</strong> 这是产品默认推荐路径：让应用自己生成授权链接、自动打开浏览器，并在回调回来后自动完成保存。</p><ol><li>切到 <code>OAuth</code> 标签页。</li><li>先复制授权链接：弹窗打开后会自动调用 <code>prepare_oauth_url</code> 预生成 URL（前端调用见 <code>AddAccountDialog.tsx:111-125</code>；后端生成与监听见 <code>oauth_server.rs</code>）。</li><li>点 <strong>Start OAuth</strong>（对应前端 <code>startOAuthLogin()</code> / 后端 <code>start_oauth_login</code>），让应用打开默认浏览器并开始等待回调。</li></ol><p><strong>你应该看到</strong>：</p><ul><li>弹窗里出现一条可复制的授权链接（事件名：<code>oauth-url-generated</code>）</li><li>浏览器打开 Google 授权页；授权后会跳转到一个本地地址，并显示“Authorization Successful!”（<code>oauth_success_html()</code>）</li></ul><h3 id="第-3-步-oauth-没自动完成时-用-完成-oauth-手动收尾" tabindex="-1">第 3 步：OAuth 没自动完成时，用“完成 OAuth”手动收尾 <a class="header-anchor" href="#第-3-步-oauth-没自动完成时-用-完成-oauth-手动收尾" aria-label="Permalink to &quot;第 3 步：OAuth 没自动完成时，用“完成 OAuth”手动收尾&quot;">​</a></h3><p><strong>为什么</strong> OAuth 流程分两段：浏览器授权得到 <code>code</code>，再由应用用 <code>code</code> 换 token。就算你没点“Start OAuth”，只要你手动打开了授权链接并完成回调，弹窗也会尝试自动收尾；如果没收尾成功，你可以手动点一次。</p><ol><li>如果你是“把链接复制到自己的浏览器里打开”（而不是默认浏览器），授权回调回来后，应用会收到 <code>oauth-callback-received</code> 事件，并自动调用 <code>completeOAuthLogin()</code>（见 <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx:67-109</code>）。</li><li>如果你没看到自动完成，点击弹窗里的 <strong>Finish OAuth</strong>（对应后端 <code>complete_oauth_login</code>）。</li></ol><p><strong>你应该看到</strong>：弹窗提示成功并自动关闭；<code>Accounts</code> 列表出现新账号。</p><div class="tip custom-block"><p class="custom-block-title">小技巧：遇到回调连不上优先复制链接</p><p>后端会尽量同时监听 IPv6 <code>::1</code> 与 IPv4 <code>127.0.0.1</code>，并根据监听情况选择 <code>localhost/127.0.0.1/[::1]</code> 作为回调地址，主要是为了规避“浏览器把 localhost 解析到 IPv6”导致的连接失败。（见 <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>）</p></div><h3 id="第-4-步-用-refresh-token-手动添加-支持批量" tabindex="-1">第 4 步：用 Refresh Token 手动添加（支持批量） <a class="header-anchor" href="#第-4-步-用-refresh-token-手动添加-支持批量" aria-label="Permalink to &quot;第 4 步：用 Refresh Token 手动添加（支持批量）&quot;">​</a></h3><p><strong>为什么</strong> 当你拿不到 <code>refresh_token</code>（或者你更偏向“可迁移资产”）时，直接用 Refresh Token 添加更可控。</p><ol><li>切到 <code>Refresh Token</code> 标签页。</li><li>把 <code>refresh_token</code> 粘贴到文本框。</li></ol><p>支持的输入形式（前端会解析并批量添加）：</p><table tabindex="0"><thead><tr><th>输入类型</th><th>例子</th><th>解析逻辑</th></tr></thead><tbody><tr><td>纯 token 文本</td><td><code>1//abc...</code></td><td>正则提取：<code>/1\\/\\/[a-zA-Z0-9_\\-]+/g</code>（见 <code>AddAccountDialog.tsx:213-220</code>）</td></tr><tr><td>夹在一大段文本里</td><td>日志/导出文本里包含多个 <code>1//...</code></td><td>正则批量提取并去重（见 <code>AddAccountDialog.tsx:213-224</code>）</td></tr><tr><td>JSON 数组</td><td><code>[{&quot;refresh_token&quot;:&quot;1//...&quot;}]</code></td><td>解析数组并取 <code>item.refresh_token</code>（见 <code>AddAccountDialog.tsx:198-207</code>）</td></tr></tbody></table><p>点 <strong>Confirm</strong> 后，弹窗会按 token 数量逐个调用 <code>onAdd(&quot;&quot;, token)</code>（见 <code>AddAccountDialog.tsx:231-248</code>），最终落到后端 <code>add_account</code>。</p><p><strong>你应该看到</strong>：</p><ul><li>弹窗显示批量进度（例如 <code>1/5</code>）</li><li>成功后 <code>Accounts</code> 列表出现新账号</li></ul><h3 id="第-5-步-确认-账号池已可用" tabindex="-1">第 5 步：确认“账号池已可用” <a class="header-anchor" href="#第-5-步-确认-账号池已可用" aria-label="Permalink to &quot;第 5 步：确认“账号池已可用”&quot;">​</a></h3><p><strong>为什么</strong> 添加成功不等于“马上能稳定用”。后端会在添加后自动触发一次“刷新配额”，并在 Proxy 运行时尝试 reload token pool，让变更立刻生效。</p><p>你可以用下面 2 个信号确认：</p><ol><li>账号出现在列表里，并显示邮箱（邮箱来自后端 <code>get_user_info</code>，不是你输入的 email）。</li><li>账号配额/订阅信息开始刷新（后端会自动调用 <code>internal_refresh_account_quota</code>）。</li></ol><p><strong>你应该看到</strong>：添加后不需要手动点刷新，账号会开始出现配额信息（是否成功以界面实际展示为准）。</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>账号列表里能看到新增账号的邮箱</li><li>没有停留在“loading”状态超过你能接受的时间（OAuth 回调完成后应该很快收尾）</li><li>如果你正在运行 Proxy，新增账号能很快参与调度（后端会尝试 reload）</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="_1-oauth-提示-未获取到-refresh-token" tabindex="-1">1) OAuth 提示“未获取到 Refresh Token” <a class="header-anchor" href="#_1-oauth-提示-未获取到-refresh-token" aria-label="Permalink to &quot;1) OAuth 提示“未获取到 Refresh Token”&quot;">​</a></h3><p>后端在 <code>start_oauth_login/complete_oauth_login</code> 会显式检查 <code>refresh_token</code> 是否存在；如果不存在，会返回一段带解决方案的错误信息（见 <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs:45-56</code>）。</p><p>按源码提示的处理方式：</p><ol><li>打开 <code>https://myaccount.google.com/permissions</code></li><li>撤销 <strong>Antigravity Tools</strong> 的访问权限</li><li>回到应用重新走 OAuth</li></ol><blockquote><p>你也可以直接改走本课的 Refresh Token 通道。</p></blockquote><h3 id="_2-浏览器提示-localhost-refused-to-connect" tabindex="-1">2) 浏览器提示 <code>localhost refused to connect</code> <a class="header-anchor" href="#_2-浏览器提示-localhost-refused-to-connect" aria-label="Permalink to &quot;2) 浏览器提示 `localhost refused to connect`&quot;">​</a></h3><p>OAuth 回调需要浏览器请求本地回调地址。为降低失败率，后端会：</p><ul><li>尝试同时监听 <code>127.0.0.1</code> 与 <code>::1</code></li><li>两者都可用时才使用 <code>localhost</code>，否则强制用 <code>127.0.0.1</code> 或 <code>[::1]</code></li></ul><p>对应实现见 <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>。</p><h3 id="_3-切换到别的标签页会取消-oauth-准备" tabindex="-1">3) 切换到别的标签页会取消 OAuth 准备 <a class="header-anchor" href="#_3-切换到别的标签页会取消-oauth-准备" aria-label="Permalink to &quot;3) 切换到别的标签页会取消 OAuth 准备&quot;">​</a></h3><p>当弹窗从 <code>OAuth</code> 切到其他 tab 时，前端会调用 <code>cancelOAuthLogin()</code> 并清空 URL（见 <code>AddAccountDialog.tsx:127-136</code>）。</p><p>如果你正在授权过程中，别急着切 tab。</p><h3 id="_4-refresh-token-的正确-错误示例" tabindex="-1">4) Refresh Token 的正确/错误示例 <a class="header-anchor" href="#_4-refresh-token-的正确-错误示例" aria-label="Permalink to &quot;4) Refresh Token 的正确/错误示例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>例子</th><th>是否会被识别</th><th>原因</th></tr></thead><tbody><tr><td><code>1//0gAbC...</code></td><td>✓</td><td>符合 <code>1//</code> 前缀规则（见 <code>AddAccountDialog.tsx:215-219</code>）</td></tr><tr><td><code>ya29.a0...</code></td><td>✗</td><td>不符合前端提取规则，会被当成无效输入</td></tr></tbody></table><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>OAuth：适合“快”，也支持复制链接到你常用浏览器并自动/手动收尾</li><li>Refresh Token：适合“稳”和“可迁移”，并支持从文本/JSON 批量提取 <code>1//...</code></li><li>拿不到 <code>refresh_token</code> 时，按错误提示撤销授权后重做，或直接改走 Refresh Token</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><p>下一课我们做一件更踏实的事：把账号池变成“可迁移资产”。</p><blockquote><p>去学 <strong><a href="./../backup-migrate/">账号备份与迁移：导入/导出、V1/DB 热迁移</a></strong>。</p></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>Accounts 页面挂载添加弹窗</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L267-L731" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>267-731</td></tr><tr><td>OAuth URL 预生成 + 回调事件自动收尾</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L49-L125" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>49-125</td></tr><tr><td>OAuth 回调事件触发 <code>completeOAuthLogin()</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L67-L109" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>67-109</td></tr><tr><td>Refresh Token 批量解析与去重</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L185-L268" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>185-268</td></tr><tr><td>前端调用 Tauri commands（add/OAuth/cancel）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/services/accountService.ts#L5-L91" target="_blank" rel="noreferrer"><code>src/services/accountService.ts</code></a></td><td>5-91</td></tr><tr><td>后端 add_account：忽略 email、用 refresh_token 获取真实邮箱并落盘</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>后端 OAuth：检查 refresh_token 缺失并给出撤销授权方案</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L38-L79" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>38-79</td></tr><tr><td>OAuth 回调 server：同时监听 IPv4/IPv6 并选择 redirect_uri</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/oauth_server.rs#L43-L113" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/oauth_server.rs</code></a></td><td>43-113</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>关键事件名</strong>：</p><ul><li><code>oauth-url-generated</code>：后端生成 OAuth URL 后发给前端（见 <code>oauth_server.rs:250-252</code>）</li><li><code>oauth-callback-received</code>：后端收到回调并解析到 code 后通知前端（见 <code>oauth_server.rs:177-180</code> / <code>oauth_server.rs:232-235</code>）</li></ul><p><strong>关键命令</strong>：</p><ul><li><code>prepare_oauth_url</code>：预生成授权链接并启动回调监听（见 <code>src-tauri/src/commands/mod.rs:469-473</code>）</li><li><code>start_oauth_login</code>：打开默认浏览器并等待回调（见 <code>src-tauri/src/commands/mod.rs:339-401</code>）</li><li><code>complete_oauth_login</code>：不打开浏览器，只等待回调并完成换 token（见 <code>src-tauri/src/commands/mod.rs:405-467</code>）</li><li><code>add_account</code>：用 refresh_token 落盘账号（见 <code>src-tauri/src/commands/mod.rs:19-60</code>）</li></ul></details>',67)])])}const b=o(c,[["render",d]]);export{g as __pageData,b as default};
